examples.original_ir:
define float @test(i1 %c, float noundef %a, float noundef %b) {
entry:
  br i1 %c, label %if, label %else

if:
  br label %join

else:
  br label %join

join:
  %phi = phi nnan ninf float [ %a, %if ], [ %b, %else ]
  %fr = freeze float %phi
  ret float %fr
}

